73	char compare_1v2_items_specific(int item_curr, int item_prev, int item_s_aux) {
74	    // Assuming item_curr, item_prev, item_s_aux are distinct indices as per problem context
75	    // L = {item_curr}, R = {item_prev, item_s_aux}
76	    // L and R must be disjoint, already true. Each set non-empty.
77	    // Items within R must be distinct (item_prev != item_s_aux). This is handled by caller logic in X_j estimation.
78	    
79	    std::pair<int, int> R_pair_key = {std::min(item_prev, item_s_aux), std::max(item_prev, item_s_aux)};
80	
81	    auto it_LHS = comparison_results_cache_1v2_specific.find(item_curr);
82	    if (it_LHS != comparison_results_cache_1v2_specific.end()) {
83	        auto it_RHS = it_LHS->second.find(R_pair_key);
84	        if (it_RHS != it_LHS->second.end()) {
85	            return it_RHS->second;
86	        }
87	    }
88	
89	    if (queries_made >= Q_total_global) {
90	        return '='; 
91	    }
92	
93	    char res_direct = perform_query_actual({item_curr}, {item_prev, item_s_aux});
94	    comparison_results_cache_1v2_specific[item_curr][R_pair_key] = res_direct;
95	    return res_direct;
96	}
