            int g2 = rng_engine() % D;
            while (g2 == g1) g2 = rng_engine() % D;
            if (group_items_vec[g1].empty() || group_items_vec[g2].empty()) continue;

            int item1 = group_items_vec[g1][rng_engine() % group_items_vec[g1].size()];
            int item2 = group_items_vec[g2][rng_engine() % group_items_vec[g2].size()];

            long long w1 = weights_ll[item1];
            long long w2 = weights_ll[item2];

            long long ns1 = group_sums[g1] - w1 + w2;
            long long ns2 = group_sums[g2] - w2 + w1;

            double new_sum_sq = current_sum_sq;
            new_sum_sq -= (double)group_sums[g1] * group_sums[g1];
            new_sum_sq -= (double)group_sums[g2] * group_sums[g2];
            new_sum_sq += (double)ns1 * ns1;
            new_sum_sq += (double)ns2 * ns2;
            double new_var = new_sum_sq / D - mean_sum * mean_sum;

            double delta = new_var - current_var;
            if (delta < 0 || (T > T_min && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                current_sum_sq = new_sum_sq;
                group_sums[g1] = ns1;
                group_sums[g2] = ns2;
                assignment[item1] = g2;
                assignment[item2] = g1;

                int pos1 = item_pos_in_group[item1];
                int last1 = group_items_vec[g1].back();
                if (item1 != last1) {
                    group_items_vec[g1][pos1] = last1;
                    item_pos_in_group[last1] = pos1;
                }
                group_items_vec[g1].pop_back();

                int pos2 = item_pos_in_group[item2];
                int last2 = group_items_vec[g2].back();
                if (item2 != last2) {
                    group_items_vec[g2][pos2] = last2;
                    item_pos_in_group[last2] = pos2;
                }
                group_items_vec[g2].pop_back();

                group_items_vec[g2].push_back(item1);
                item_pos_in_group[item1] = group_items_vec[g2].size() - 1;
                group_items_vec[g1].push_back(item2);
                item_pos_in_group[item2] = group_items_vec[g1].size() - 1;

                if (current_var < best_var) {
                    best_var = current_var;
                    best_assignment = assignment;
                }
            }
        } else {
            // 3-chain: move item1 from g1->g2, item2 from g2->g3
            if (D < 3) continue;
            int g1 = rng_engine() % D;
            int g2 = rng_engine() % D;
            while (g2 == g1) g2 = rng_engine() % D;
            int g3 = rng_engine() % D;
            while (g3 == g1 || g3 == g2) g3 = rng_engine() % D;

            if (group_items_vec[g1].empty() || group_items_vec[g2].empty()) continue;

            int item1 = group_items_vec[g1][rng_engine() % group_items_vec[g1].size()];
            int item2 = group_items_vec[g2][rng_engine() % group_items_vec[g2].size()];

            long long w1 = weights_ll[item1];
            long long w2 = weights_ll[item2];

            long long ns1 = group_sums[g1] - w1;
            long long ns2 = group_sums[g2] + w1 - w2;
            long long ns3 = group_sums[g3] + w2;

            double new_sum_sq = current_sum_sq;
            new_sum_sq -= (double)group_sums[g1] * group_sums[g1];
            new_sum_sq -= (double)group_sums[g2] * group_sums[g2];
            new_sum_sq -= (double)group_sums[g3] * group_sums[g3];
            new_sum_sq += (double)ns1 * ns1;
            new_sum_sq += (double)ns2 * ns2;
            new_sum_sq += (double)ns3 * ns3;
            double new_var = new_sum_sq / D - mean_sum * mean_sum;

            double delta = new_var - current_var;
            if (delta < 0 || (T > T_min && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                current_sum_sq = new_sum_sq;
                group_sums[g1] = ns1;
                group_sums[g2] = ns2;
                group_sums[g3] = ns3;

                // Move item1 from g1 to g2
                assignment[item1] = g2;
                int pos1 = item_pos_in_group[item1];
                int last1 = group_items_vec[g1].back();
                if (item1 != last1) {
                    group_items_vec[g1][pos1] = last1;
                    item_pos_in_group[last1] = pos1;
                }
                group_items_vec[g1].pop_back();
                group_items_vec[g2].push_back(item1);
                item_pos_in_group[item1] = group_items_vec[g2].size() - 1;

                // Move item2 from g2 to g3
                assignment[item2] = g3;
                int pos2 = item_pos_in_group[item2];
                int last2 = group_items_vec[g2].back();
                if (item2 != last2) {
                    group_items_vec[g2][pos2] = last2;
                    item_pos_in_group[last2] = pos2;
                }
                group_items_vec[g2].pop_back();
                group_items_vec[g3].push_back(item2);
                item_pos_in_group[item2] = group_items_vec[g3].size() - 1;

                if (current_var < best_var) {
                    best_var = current_var;
                    best_assignment = assignment;
                }
            }
        }
    }

    // Use best found assignment
    for (int i = 0; i < N; i++) {
        std::cout << best_assignment[i] << (i == N - 1 ? "" : " ");
    }
    std::cout << std::endl;
    return 0;
}
